simple_types.code:
type MCP9808_Status is (
                        Ok,
                        Init_Error,
                        I2C_Not_Ok
                       );

type Resolution is (Half,
                    Quarter,
                    Eighth,
                    Sixteenth
                   );

record_types.code:
type Ambient_Status is record
   GorE_Upper         : Boolean;
   Less_Than_Lower    : Boolean;
   GorE_Critical      : Boolean;
end record;

type Op_Status is record
   I2C_Status : HAL.I2C.I2C_Status;
   E_Status   : MCP9808_Status;
end record;

